test('isSameRootCause returns true only when exitCode and command match', () => {
  const previous = { exitCode: 1, command: 'npm test' };
  assert.strictEqual(
    isSameRootCause({ exitCode: 1, command: 'npm test' }, previous),
    true
  );
  assert.strictEqual(
